New-Item -ItemType Directory -Force -Path "screens" | Out-Null

foreach ($screen in $screens) {
    Write-Host "Downloading $($screen.id)..."
    try {
        Invoke-WebRequest -Uri $screen.html -OutFile "screens\$($screen.id).html" -UseBasicParsing
        Invoke-WebRequest -Uri $screen.img -OutFile "screens\$($screen.id).png" -UseBasicParsing
    } catch {
        Write-Error "Failed to download $($screen.id): $_"
    }
}
Write-Host "Done!"
